option.value:
/* 1. 基礎容器：強制白色背景，深色文字 */
body, .markdown-body, #write {
    background-color: #ffffff !important;
    color: #24292e !important;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    line-height: 1.6;
    padding: 40px !important;
}

/* 2. 標題：使用深藍色調增加層次感 */
h1, h2, h3, h4, h5, h6 {
    color: #0550ae !important; /* 豐富的深藍色 */
    margin-top: 24px;
    margin-bottom: 16px;
    font-weight: 600;
    line-height: 1.25;
}

h1 { font-size: 2em; border-bottom: 2px solid #d0d7de !important; padding-bottom: 0.3em; }
h2 { font-size: 1.5em; border-bottom: 1px solid #d0d7de !important; padding-bottom: 0.3em; }

/* 3. 一般文字、清單、強調字體 */
p, li, span, div, strong, b, em, i {
    color: #24292e !important; /* 強制所有文字為深灰色/黑色 */
}

/* 4. 內嵌小標籤 (Inline Code)：解決你截圖中 MessageLogEntry 看不見的問題 */
code {
    color: #cf222e !important; /* 鮮艷的紅色，適合標註類別名 */
    background-color: #afb8c133 !important; /* 淺灰色背景 */
    padding: 0.2em 0.4em !important;
    border-radius: 6px !important;
    font-family: ui-monospace, SFMono-Regular, SF Mono, Menlo, Consolas, Liberation Mono, monospace !important;
    font-size: 85% !important;
}

/* 5. 區塊程式碼 (Code Block) */
pre {
    background-color: #f6f8fa !important;
    border: 1px solid #d0d7de !important;
    border-radius: 6px !important;
    padding: 16px !important;
    overflow: auto;
}

pre code {
    color: #1f2328 !important; /* 代碼內文顏色 */
    background: transparent !important;
    padding: 0 !important;
}

/* 6. 表格：針對截圖中的需求摘要表優化 */
table {
    border-collapse: collapse !important;
    width: 100% !important;
    margin: 16px 0 !important;
    background-color: #ffffff !important;
}

table th {
    background-color: #f0f3f6 !important; /* 標題欄淺灰藍色 */
    color: #1f2328 !important;
    font-weight: 600 !important;
    border: 1px solid #d0d7de !important;
    padding: 8px 13px !important;
}

table td {
    border: 1px solid #d0d7de !important;
    padding: 8px 13px !important;
    color: #24292e !important;
}

table tr:nth-child(2n) {
    background-color: #f6f8fa !important; /* 隔行變色 */
}

/* 7. 引用區塊 (Blockquote)：側邊加上亮眼的顏色 */
blockquote {
    padding: 0 1em !important;
    color: #57606a !important;
    border-left: 0.25em solid #0969da !important; /* 藍色側邊線 */
    background-color: #f8f9fa !important;
    margin: 0 !important;
}

/* 8. 連結與分隔線 */
a {
    color: #0969da !important;
    text-decoration: none !important;
}

a:hover {
    text-decoration: underline !important;
}

hr {
    height: 0.25em !important;
    background-color: #d0d7de !important;
    border: 0 !important;
    margin: 24px 0 !important;
}

/* 9. 圖片背景預防 */
img {
    max-width: 100% !important;
    background-color: transparent !important;
}
